(function () {
    'use strict';
    const root = document.querySelector('[data-vh360-studio-dashboard]');
    const engine = window.VH360StudioOverlayEngine;
    const compositor = window.VH360StudioCompositor;
    const config = window.vh360StudioDashboard || {};
    const strings = (config.strings && config.strings.countdown) || {};
    if (!root || !engine || !compositor) { return; }
    const $ = (sel) => root.querySelector(sel);
    const text = (key) => strings[key] || key;
    const listeners = [];
    let refreshTimer = null;
    const state = { presets: [], selectedId: 0, staged: false, previewSource: compositor.hasPreviewSource(), programOutput: compositor.hasProgramOutput(), destroyed: false };
    const els = {
        preset: $('[data-countdown-preset]'), mode: $('[data-countdown-mode]'), hours: $('[data-countdown-hours]'), minutes: $('[data-countdown-minutes]'), seconds: $('[data-countdown-seconds]'), target: $('[data-countdown-target]'), durationFields: $('[data-countdown-duration-fields]'), targetFields: $('[data-countdown-target-fields]'), label: $('[data-countdown-label]'), message: $('[data-countdown-message]'), previewStatus: $('[data-countdown-preview-status]'), programStatus: $('[data-countdown-program-status]'), remaining: $('[data-countdown-remaining]'), status: $('[data-countdown-status]'), stage: $('[data-countdown-stage]'), clearPreview: $('[data-countdown-clear-preview]'), take: $('[data-countdown-take]'), update: $('[data-countdown-update]'), hide: $('[data-countdown-hide]'), start: $('[data-countdown-start]'), pause: $('[data-countdown-pause]'), resume: $('[data-countdown-resume]'), reset: $('[data-countdown-reset]'), template: $('[data-countdown-template]'), position: $('[data-countdown-position]'), scale: $('[data-countdown-scale]'), accent: $('[data-countdown-accent]'), bg: $('[data-countdown-bg]'), bgOpacity: $('[data-countdown-bg-opacity]'), timerColor: $('[data-countdown-timer-color]'), labelColor: $('[data-countdown-label-color]'), name: $('[data-countdown-name]'), endBehavior: $('[data-countdown-end-behavior]'), messageDuration: $('[data-countdown-message-duration]'), entrance: $('[data-countdown-entrance]'), exit: $('[data-countdown-exit]'), durationMs: $('[data-countdown-duration-ms]'), save: $('[data-countdown-save]'), saveNew: $('[data-countdown-save-new]'), duplicate: $('[data-countdown-duplicate]'), delete: $('[data-countdown-delete]')
    };
    function clone(v) { return JSON.parse(JSON.stringify(v)); }
    function clamp(v,min,max){ return Math.min(Math.max(v,min),max); }
    function validHex(v,f){ return /^#[0-9a-f]{6}$/i.test(v||'') ? v : f; }
    function defaultConfig(){ return { id:0,type:'countdown',name:'',content:{label:'Service Begins In',endMessage:'Service Is Beginning'},timer:{mode:'duration',durationSeconds:600,targetLocalDateTime:'',endBehavior:'show_message',messageDurationSeconds:5},style:{template:'center_card',position:'top_right',scale:100,accentColor:'#4f46e5',backgroundColor:'#0f172a',backgroundOpacity:88,timerColor:'#ffffff',labelColor:'#dbeafe'},behavior:{entrance:'fade',exit:'fade',durationMs:300} }; }
    function durationSeconds(){ return clamp((Number(els.hours.value)||0)*3600+(Number(els.minutes.value)||0)*60+(Number(els.seconds.value)||0),1,86400); }
    function currentConfig(){ const c=defaultConfig(); c.id=state.selectedId; c.name=(els.name.value||els.label.value||text('untitled')).trim(); c.content.label=(els.label.value||'').trim().slice(0,120); c.content.endMessage=(els.message.value||'').trim().slice(0,160); c.timer.mode=els.mode.value==='target_time'?'target_time':'duration'; c.timer.durationSeconds=durationSeconds(); c.timer.targetLocalDateTime=els.target.value||''; c.timer.endBehavior=['hold_zero','show_message','hide'].includes(els.endBehavior.value)?els.endBehavior.value:'show_message'; c.timer.messageDurationSeconds=clamp(Number(els.messageDuration.value)||0,0,300); c.style.template=['full_screen','center_card','lower_center','corner'].includes(els.template.value)?els.template.value:'center_card'; c.style.position=['top_left','top_right','bottom_left','bottom_right'].includes(els.position.value)?els.position.value:'top_right'; c.style.scale=clamp(Number(els.scale.value)||100,75,140); c.style.accentColor=validHex(els.accent.value,'#4f46e5'); c.style.backgroundColor=validHex(els.bg.value,'#0f172a'); c.style.backgroundOpacity=clamp(Number(els.bgOpacity.value)||88,0,100); c.style.timerColor=validHex(els.timerColor.value,'#ffffff'); c.style.labelColor=validHex(els.labelColor.value,'#dbeafe'); c.behavior.entrance=els.entrance.value==='none'?'none':'fade'; c.behavior.exit=els.exit.value==='none'?'none':'fade'; c.behavior.durationMs=clamp(Number(els.durationMs.value)||0,0,2000); return c; }
    function runtimeReady(c){ return { status:'ready', remainingMs:c.timer.durationSeconds*1000, endAtEpochMs:0, targetEpochMs:0, pausedRemainingMs:0, completedAtEpochMs:0, messageUntilEpochMs:0 }; }
    function remaining(rt){ if(!rt) return 0; if(rt.status==='running'&&rt.endAtEpochMs) return Math.max(0,rt.endAtEpochMs-Date.now()); if(rt.status==='paused') return Math.max(0,rt.pausedRemainingMs||0); return Math.max(0,rt.remainingMs||0); }
    function setStatus(msg,type){ els.status.textContent=msg||''; els.status.dataset.statusType=type||'info'; }
    function validate(){ const c=currentConfig(); if(c.timer.mode==='duration' && c.timer.durationSeconds<1){ setStatus(text('invalidDuration'),'warning'); return false; } if(c.timer.mode==='target_time'){ const time=Date.parse(c.timer.targetLocalDateTime); if(!time || time<=Date.now()){ setStatus(text('futureTarget'),'warning'); return false; } } return true; }
    function applyConfig(c){ c=Object.assign(defaultConfig(),c||{}); c.content=Object.assign(defaultConfig().content,c.content||{}); c.timer=Object.assign(defaultConfig().timer,c.timer||{}); c.style=Object.assign(defaultConfig().style,c.style||{}); c.behavior=Object.assign(defaultConfig().behavior,c.behavior||{}); state.selectedId=Number(c.id)||0; els.name.value=c.name||''; els.label.value=c.content.label||''; els.message.value=c.content.endMessage||''; els.mode.value=c.timer.mode; els.target.value=c.timer.targetLocalDateTime||''; const d=Number(c.timer.durationSeconds)||600; els.hours.value=Math.floor(d/3600); els.minutes.value=Math.floor((d%3600)/60); els.seconds.value=d%60; els.endBehavior.value=c.timer.endBehavior; els.messageDuration.value=c.timer.messageDurationSeconds; els.template.value=c.style.template; els.position.value=c.style.position; els.scale.value=c.style.scale; els.accent.value=c.style.accentColor; els.bg.value=c.style.backgroundColor; els.bgOpacity.value=c.style.backgroundOpacity; els.timerColor.value=c.style.timerColor; els.labelColor.value=c.style.labelColor; els.entrance.value=c.behavior.entrance; els.exit.value=c.behavior.exit; els.durationMs.value=c.behavior.durationMs; if(els.preset) els.preset.value=state.selectedId?String(state.selectedId):''; modeFields(); updatePreview(); render(); }
    function modeFields(){ const target=els.mode.value==='target_time'; els.durationFields.hidden=target; els.targetFields.hidden=!target; }
    function updatePreview(){ if(state.staged) engine.stage('countdown',currentConfig(),{runtime:runtimeReady(currentConfig())}); }
    function snap(){ return engine.getState(); }
    function render(){ const s=snap(); const p=s.preview.countdown; const g=s.program.countdown; const rt=g&&g.runtime; els.previewStatus.textContent=p?text('stagedShort'):text('notStaged'); els.programStatus.textContent=g?(rt&&rt.status?rt.status:text('ready')):text('notLive'); els.remaining.textContent=engine.formatCountdown ? engine.formatCountdown(remaining(rt || (p&&p.runtime))) : ''; els.stage.disabled=!state.previewSource||!validate(); els.clearPreview.disabled=!p; els.take.disabled=!p||!state.programOutput; els.update.disabled=!p||!g; els.hide.disabled=!g; els.start.disabled=!g||!(rt.status==='ready'||rt.status==='complete'); els.pause.disabled=!g||rt.status!=='running'; els.resume.disabled=!g||rt.status!=='paused'; els.reset.disabled=!g; els.delete.disabled=!state.selectedId; scheduleRefresh(rt); }
    function scheduleRefresh(rt){ if(refreshTimer) window.clearTimeout(refreshTimer); refreshTimer=null; if(rt&&(rt.status==='running'||(rt.status==='message'&&rt.messageUntilEpochMs))){ refreshTimer=window.setTimeout(render,500); } }
    async function api(path,o){ const r=await fetch((config.restRoot||'')+path,Object.assign({headers:{'Content-Type':'application/json','X-WP-Nonce':config.nonce||''}},o||{})); if(!r.ok) throw new Error('rest'); return r.json(); }
    function renderPresets(){ const v=els.preset.value; els.preset.innerHTML='<option value="">'+text('unsaved')+'</option>'; state.presets.forEach((p)=>{ const o=document.createElement('option'); o.value=String(p.id); o.textContent=p.name; els.preset.appendChild(o); }); els.preset.value=v; }
    async function load(){ setStatus(text('loading'),'info'); try{ const items=await api('/overlays?type=countdown'); if(state.destroyed)return; state.presets=items; renderPresets(); setStatus(text('loaded'),'success'); }catch(e){ if(!state.destroyed)setStatus(text('loadFailed'),'warning'); } }
    function stage(){ if(!state.previewSource){setStatus(text('choosePreview'),'warning');return;} if(!validate())return; const c=currentConfig(); state.staged=true; engine.stage('countdown',c,{runtime:runtimeReady(c)}); setStatus(text('staged'),'success'); render(); }
    function take(){ if(!state.programOutput){setStatus(text('chooseProgram'),'warning');return;} const c=currentConfig(); engine.takeToProgram('countdown',{runtime:runtimeReady(c)}); setStatus(text('taken'),'success'); render(); }
    function update(){ engine.updateProgram('countdown',{preserveRuntime:true}); setStatus(text('updated'),'success'); if(['full_screen','lower_center'].includes(els.template.value)) setStatus(els.template.value==='full_screen'?text('fullWarning'):text('lowerWarning'),'warning'); render(); }
    function start(){ const item=snap().program.countdown; if(!item)return; const c=item.config; const rt=item.runtime||runtimeReady(c); if(c.timer.mode==='target_time'){ const target=Date.parse(c.timer.targetLocalDateTime); if(!target||target<=Date.now()){setStatus(text('futureTarget'),'warning');return;} rt.targetEpochMs=target; rt.endAtEpochMs=target; } else { rt.endAtEpochMs=Date.now()+Math.max(1,rt.remainingMs||c.timer.durationSeconds*1000); } rt.status='running'; engine.setRuntime('program','countdown',rt); setStatus(text('started'),'success'); render(); }
    function pause(){ const rt=engine.getRuntime('program','countdown'); rt.pausedRemainingMs=remaining(rt); rt.remainingMs=rt.pausedRemainingMs; rt.status='paused'; engine.setRuntime('program','countdown',rt); setStatus(text('paused'),'success'); render(); }
    function resume(){ const item=snap().program.countdown; const rt=item.runtime; if(item.config.timer.mode==='duration') rt.endAtEpochMs=Date.now()+(rt.pausedRemainingMs||rt.remainingMs); rt.status='running'; engine.setRuntime('program','countdown',rt); setStatus(text('resumed'),'success'); render(); }
    function reset(){ const c=currentConfig(); engine.setRuntime('program','countdown',runtimeReady(c)); engine.updateProgram('countdown',{preserveRuntime:false,runtime:runtimeReady(c)}); setStatus(text('reset'),'success'); render(); }
    function clearPreview(){ state.staged=false; engine.clearPreview('countdown'); render(); }
    function hide(){ engine.hideProgram('countdown'); setStatus(text('hidden'),'success'); render(); }
    async function save(asNew){ const c=currentConfig(); try{ const item=await api(asNew||!state.selectedId?'/overlays':'/overlays/'+state.selectedId,{method:asNew||!state.selectedId?'POST':'PUT',body:JSON.stringify({type:'countdown',name:c.name,config:c})}); if(state.destroyed)return; const i=state.presets.findIndex(p=>Number(p.id)===Number(item.id)); if(i>=0)state.presets[i]=item; else state.presets.unshift(item); state.selectedId=item.id; renderPresets(); els.preset.value=String(item.id); setStatus(text('saved'),'success'); }catch(e){ if(!state.destroyed)setStatus(text('saveFailed'),'warning'); } render(); }
    async function del(){ if(!state.selectedId||!confirm(text('confirmDelete')))return; const focus=els.preset; try{ await api('/overlays/'+state.selectedId,{method:'DELETE'}); if(state.destroyed)return; state.presets=state.presets.filter(p=>Number(p.id)!==Number(state.selectedId)); state.selectedId=0; renderPresets(); setStatus(text('deleted'),'success'); focus.focus(); }catch(e){ if(!state.destroyed)setStatus(text('deleteFailed'),'warning'); } render(); }
    function on(t,e,h){ if(!t)return; t.addEventListener(e,h); listeners.push({t,e,h}); }
    [els.mode,els.hours,els.minutes,els.seconds,els.target,els.label,els.message,els.template,els.position,els.scale,els.accent,els.bg,els.bgOpacity,els.timerColor,els.labelColor,els.name,els.endBehavior,els.messageDuration,els.entrance,els.exit,els.durationMs].forEach(el=>{ on(el,'input',()=>{modeFields();updatePreview();render();}); on(el,'change',()=>{modeFields();updatePreview();render();}); });
    on(els.preset,'change',()=>{ if(!els.preset.value){state.selectedId=0;render();return;} const p=state.presets.find(i=>String(i.id)===els.preset.value); if(p)applyConfig(Object.assign(clone(p.config),{id:p.id,name:p.name})); });
    on(els.stage,'click',stage); on(els.clearPreview,'click',clearPreview); on(els.take,'click',take); on(els.update,'click',update); on(els.hide,'click',hide); on(els.start,'click',start); on(els.pause,'click',pause); on(els.resume,'click',resume); on(els.reset,'click',reset); on(els.save,'click',()=>save(false)); on(els.saveNew,'click',()=>save(true)); on(els.duplicate,'click',()=>{state.selectedId=0;save(true);}); on(els.delete,'click',del);
    on(root,'vh360:studio:preview-source-change',e=>{state.previewSource=Boolean(e.detail&&e.detail.sourceId);render();}); on(root,'vh360:studio:program-source-change',e=>{state.programOutput=Boolean(e.detail&&e.detail.hasOutput);render();}); on(root,'vh360:studio-overlay:program-change',render); on(root,'vh360:studio-overlay:preview-change',render);
    function destroy(){ state.destroyed=true; if(refreshTimer)window.clearTimeout(refreshTimer); listeners.splice(0).forEach(({t,e,h})=>t.removeEventListener(e,h)); }
    window.VH360StudioCountdown={destroy}; applyConfig(defaultConfig()); load(); render();
}());
